<!DOCTYPE html>
<html lang="es">
<head>
  <meta charset="UTF-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1.0" />
  <title>Tourny — Gestión de Torneos de Fútbol</title>
  <link rel="preconnect" href="https://fonts.googleapis.com" />
  <link rel="preconnect" href="https://fonts.gstatic.com" crossorigin />
  <link href="https://fonts.googleapis.com/css2?family=Inter:ital,wght@0,300;0,400;0,500;1,600&display=swap" rel="stylesheet" />
  
  <style>
      :root {
      --bg:    #091413;
      --dark:  #285a48;
      --mid:   #408a71;
      --light: #b0e4cc;
      --white: #f0faf5;
      --font:  'Inter', sans-serif;
    }
    *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
    html, body { height: 100%; }
    body {
      font-family: var(--font);
      background: var(--bg);
      color: var(--white);
      overflow-x: hidden;
    }

    /* ── HERO ── */
    .hero {
      position: relative;
      min-height: 100vh;
      display: flex;
      flex-direction: column;
      align-items: center;
      justify-content: center;
      text-align: center;
      padding: 2rem;
      overflow: hidden;
    }

    /* Background image */
    .hero-bg {
      position: absolute;
      inset: 0;
      background-image: var(--field-img);
      background-size: cover;
      background-position: center;
      filter: brightness(.38) saturate(1.1);
      z-index: 0;
    }

    /* Green vignette overlay matching palette */
    .hero-overlay {
      position: absolute;
      inset: 0;
      background:
        radial-gradient(ellipse at center bottom, rgba(40,90,72,.35) 0%, transparent 65%),
        radial-gradient(ellipse at center top,    rgba(9,20,19,.7)   0%, transparent 60%),
        linear-gradient(to bottom, rgba(9,20,19,.55) 0%, rgba(9,20,19,.1) 40%, rgba(9,20,19,.6) 100%);
      z-index: 1;
    }

    /* Noise grain */
    .hero::before {
      content: '';
      position: absolute;
      inset: 0;
      background-image: url("data:image/svg+xml,%3Csvg viewBox='0 0 200 200' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='n'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='0.85' numOctaves='4' stitchTiles='stitch'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23n)' opacity='0.05'/%3E%3C/svg%3E");
      background-size: 180px 180px;
      pointer-events: none;
      z-index: 2;
      opacity: .3;
    }

    .hero-content {
      position: relative;
      z-index: 3;
      display: flex;
      flex-direction: column;
      align-items: center;
      gap: 0;
      animation: fadeUp .9s ease both;
    }
    @keyframes fadeUp {
      from { opacity: 0; transform: translateY(28px); }
      to   { opacity: 1; transform: none; }
    }

    /* ── LOGO SVG ── */
    .logo-wrap {
      display: flex;
      align-items: center;
      gap: 1rem;
      margin-bottom: 1.2rem;
    }
    .logo-svg { width: 68px; height: 68px; mix-blend-mode: screen; border-radius: 4px; }
    .logo-text {
      font-size: 3.2rem;
      font-weight: 600;
      font-style: italic;
      color: #ffffff;
      letter-spacing: .01em;
      line-height: 1;
    }

    /* ── TAGLINE ── */
    .tagline {
      font-size: clamp(.78rem, 1.5vw, .92rem);
      font-weight: 400;
      letter-spacing: .22em;
      text-transform: uppercase;
      color: rgba(176,228,204,.55);
      margin-bottom: 2.8rem;
    }

    /* ── HEADLINE ── */
    .headline {
      font-size: clamp(2.6rem, 6vw, 5.2rem);
      font-weight: 300;
      line-height: 1.08;
      letter-spacing: -.01em;
      color: var(--white);
      margin-bottom: 1.2rem;
      max-width: 16ch;
    }
    .headline strong {
      font-weight: 600;
      color: var(--light);
    }

    .sub {
      font-size: clamp(.9rem, 1.4vw, 1.05rem);
      font-weight: 300;
      color: rgba(176,228,204,.55);
      max-width: 42ch;
      line-height: 1.75;
      margin-bottom: 3rem;
    }

    /* ── CTA BUTTON ── */
    .btn-main {
      display: inline-flex;
      align-items: center;
      gap: .65rem;
      padding: 1rem 2.4rem;
      background: var(--mid);
      color: #fff;
      font-family: var(--font);
      font-size: .88rem;
      font-weight: 500;
      letter-spacing: .12em;
      text-transform: uppercase;
      border: none;
      cursor: pointer;
      text-decoration: none;
      clip-path: polygon(0 0, calc(100% - 10px) 0, 100% 10px, 100% 100%, 10px 100%, 0 calc(100% - 10px));
      transition: background .25s, transform .2s, box-shadow .25s;
      box-shadow: 0 0 0 0 rgba(64,138,113,0);
    }
    .btn-main:hover {
      background: #4fa882;
      transform: translateY(-3px);
      box-shadow: 0 12px 32px rgba(64,138,113,.35);
    }
    .btn-main svg { width: 14px; height: 14px; flex-shrink: 0; }

    /* ── SCROLL HINT ── */
    .scroll-hint {
      position: absolute;
      bottom: 2.2rem;
      left: 50%;
      transform: translateX(-50%);
      z-index: 3;
      display: flex;
      flex-direction: column;
      align-items: center;
      gap: .4rem;
      color: rgba(176,228,204,.25);
      font-size: .65rem;
      letter-spacing: .18em;
      text-transform: uppercase;
      animation: pulse 2.5s ease-in-out infinite;
    }
    @keyframes pulse { 0%,100%{opacity:.3} 50%{opacity:.7} }
    .scroll-hint svg { width: 16px; height: 16px; }

    /* ── FOOTER ── */
    footer {
      background: rgba(9,20,19,.98);
      border-top: 1px solid rgba(64,138,113,.15);
      padding: 2rem 3rem;
      display: flex;
      align-items: center;
      justify-content: space-between;
      flex-wrap: wrap;
      gap: 1rem;
    }
    .footer-logo {
      display: flex;
      align-items: center;
      gap: .5rem;
    }
    .footer-logo svg { width: 26px; height: 26px; opacity: .4; }
    .footer-logo span {
      font-size: 1rem;
      font-weight: 600;
      font-style: italic;
      color: rgba(176,228,204,.3);
      letter-spacing: .02em;
    }
    .footer-copy {
      font-size: .72rem;
      font-weight: 300;
      letter-spacing: .06em;
      color: rgba(176,228,204,.18);
    }
    .footer-links {
      display: flex;
      gap: 2rem;
      list-style: none;
    }
    .footer-links a {
      font-size: .72rem;
      letter-spacing: .1em;
      text-transform: uppercase;
      color: rgba(176,228,204,.2);
      text-decoration: none;
      transition: color .2s;
    }
    .footer-links a:hover { color: rgba(176,228,204,.5); }

    @media (max-width: 600px) {
      footer { flex-direction: column; text-align: center; align-items: center; padding: 1.8rem 1.5rem; }
      .footer-links { justify-content: center; }
    }
  </style>

</head>
<body>

  <section class="hero" id="hero">
    <div class="hero-bg" style="background-image: url('data:image/jpeg;base64,')"></div>
    <div class="hero-overlay"></div>

    <div class="hero-content">
      <!-- Logo -->
      <div class="logo-wrap">
        <img class="logo-svg" src="data:image/png;base64," alt="Tourny logo" />
        <span class="logo-text">Tourny</span>
      </div>

      <p class="tagline">Gestión de Torneos de Fútbol</p>

      <h1 class="headline">Tu torneo,<br><strong>tus reglas.</strong></h1>

      <p class="sub">
        Organizá torneos personalizados con fixture automático, tabla de posiciones en tiempo real y todo lo que tu competencia necesita.
      </p>

      <a href="/torneos/create" class="btn-main">
        <svg viewBox="0 0 16 16" fill="none" xmlns="http://www.w3.org/2000/svg">
          <path d="M8 3v10M3 8h10" stroke="currentColor" stroke-width="1.8" stroke-linecap="round"/>
        </svg>
        Crear un torneo
      </a>
    </div>

    <div class="scroll-hint">
      <svg viewBox="0 0 16 16" fill="none" xmlns="http://www.w3.org/2000/svg">
        <path d="M8 3v10M4 9l4 4 4-4" stroke="currentColor" stroke-width="1.4" stroke-linecap="round" stroke-linejoin="round"/>
      </svg>
    </div>
  </section>

  <footer>
    <div class="footer-logo">
      <img style="width:26px;height:26px;opacity:.4;filter:invert(1)" src="data:image/png;base64," alt="Tourny" img/>
      <span>Tourny</span>
    </div>
    <span class="footer-copy">© 2026 Tourny · Todos los derechos reservados</span>
    <ul class="footer-links">
      <li><a href="#">Términos</a></li>
      <li><a href="#">Privacidad</a></li>
      <li><a href="#">Contacto</a></li>
    </ul>
  </footer>

</body>
</html>